   637→
   638→    if (aVisitor.mEvent->mFlags.mBubbles || newTarget) {
   639→      if ((!aVisitor.mEvent->mFlags.mNoContentDispatch ||
   640→           item.ForceContentDispatch()) &&
   641→          !aVisitor.mEvent->PropagationStopped()) {
   642→        item.HandleEvent(aVisitor, aCd);
