   if (mManager) {
     NS_ASSERTION(aVisitor.mEvent->mCurrentTarget == nullptr,
                  "CurrentTarget should be null!");

     mManager->HandleEvent(aVisitor.mPresContext, aVisitor.mEvent,
                           &aVisitor.mDOMEvent, CurrentTarget(),
